# Let me try a comprehensive Python script to extract pricing from all sources
python3 << 'PYEOF'
import requests
import re
from bs4 import BeautifulSoup

headers = {"User-Agent": "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36"}

urls = {
    "LastPass Business": "https://lastpass.com/fp/business/",
    "LastPass Pricing": "https://lastpass.com/pricing/",
    "Dashlane Pricing": "https://www.dashlane.com/pricing",
    "Dashlane Business": "https://www.dashlane.com/business",
    "Keeper Pricing": "https://www.keepersecurity.com/pricing/",
    "Keeper Business": "https://www.keepersecurity.com/pricing/business/",
}

for name, url in urls.items():
    try:
        r = requests.get(url, headers=headers, timeout=10)
        # Look for any price patterns
        prices = re.findall(r'\$[\d,]+\.?\d*', r.text)
        if prices:
            print(f"\n{name} ({url}):")
            print(f"  Prices found: {set(prices)}")

        # Also look for pricing in script tags (JSON data)
        soup = BeautifulSoup(r.text, 'html.parser')
        for script in soup.find_all('script'):
            if script.string and '$' in script.string:
                prices_in_script = re.findall(r'\$[\d,]+\.?\d*', script.string)
                if prices_in_script:
                    print(f"  In script: {set(prices_in_script)}")
    except Exception as e:
        print(f"{name}: Error - {e}")
PYEOF

