import requests
import re

headers = {"User-Agent": "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36"}

# Try various sources for LastPass pricing
sources = [
    "https://www.pcmag.com/picks/what-is-the-best-password-manager",
    "https://www.capterra.com/password-management-software/",
]

for url in sources:
    try:
        r = requests.get(url, headers=headers, timeout=10)
        prices = re.findall(r'LastPass.*?\$[\d,]+\.?\d*', r.text, re.IGNORECASE)
        if prices:
            print(f"{url}:")
            for p in prices[:5]:
                print(f"  {p.strip()}")
    except Exception as e:
        print(f"{url}: Error - {e}")
